import { useState } from 'react';
import { getMatches } from '../api/claudeAPI';
import './Match.css';

const DEFAULT_MATERIALS = `Modular Folding Tables (120 units) — LA Memorial Coliseum
Athlete Village Bed Frames (350 units) — UCLA Olympic Village
LED Stage Lighting Rigs (80 units) — Crypto.com Arena
Event Canopy Structures (45 units) — UCLA Olympic Village
Crowd Control Barriers (200 units) — Dignity Health Sports Park
PA Speaker Systems (30 units) — Rose Bowl
Locker Units 6-Bay (60 units) — Long Beach Arena
Diesel Portable Generators (25 units) — Dignity Health Sports Park
Temporary Bleacher Sections (18 units) — Rose Bowl
Broadcast Monitor Displays (12 units) — SoFi Stadium`;

export default function Match() {
  const [orgNeeds, setOrgNeeds] = useState('');
  const [materialsText, setMaterialsText] = useState(DEFAULT_MATERIALS);
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  async function handleSubmit(e) {
    e.preventDefault();
    if (!orgNeeds.trim()) return;

    setLoading(true);
    setError(null);
    setResults(null);

    try {
      const orgProfile = { needs: orgNeeds };
      const availableMaterials = materialsText
        .split('\n')
        .map((line) => line.trim())
        .filter(Boolean);

      const data = await getMatches(orgProfile, availableMaterials);
      setResults(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  function getFitColor(score) {
    if (score >= 8) return '#2e7d32';
    if (score >= 5) return '#f57c00';
    return '#c62828';
  }

  return (
    <main className="match-page">
      <h1>Find Your Match</h1>
      <p className="match-subtitle">
        Describe your organization's needs and we'll match you with available surplus materials.
      </p>

      <form className="match-form" onSubmit={handleSubmit}>
        <label htmlFor="org-needs">Your Organization's Needs</label>
        <textarea
          id="org-needs"
          rows={4}
          placeholder="e.g. We run an after-school sports program for 200 kids and need seating, shade structures, and sound equipment for outdoor events."
          value={orgNeeds}
          onChange={(e) => setOrgNeeds(e.target.value)}
        />

        <label htmlFor="materials">Available Materials</label>
        <textarea
          id="materials"
          rows={7}
          value={materialsText}
          onChange={(e) => setMaterialsText(e.target.value)}
        />

        <button type="submit" disabled={loading || !orgNeeds.trim()}>
          {loading ? 'Finding matches…' : 'Find Matches'}
        </button>
      </form>

      {loading && (
        <div className="match-loading">
          <div className="spinner" />
          <p>Claude is finding the best matches for your organization…</p>
        </div>
      )}

      {error && (
        <div className="match-error">
          <strong>Error:</strong> {error}
        </div>
      )}

      {results && (
        <section className="match-results">
          {results.summary && (
            <p className="match-summary">{results.summary}</p>
          )}
          <div className="match-cards">
            {results.matches.map((match, i) => (
              <div key={i} className="match-card">
                <div className="match-card-header">
                  <span className="match-material">{match.material}</span>
                  <span
                    className="match-score"
                    style={{ background: getFitColor(match.fit_score) }}
                  >
                    {match.fit_score}/10
                  </span>
                </div>
                <p className="match-reason">{match.reason}</p>
              </div>
            ))}
          </div>
        </section>
      )}
    </main>
  );
}
